import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaCalendarAlt, FaBookmark, FaRegBookmark } from 'react-icons/fa';
import { AuthContext } from '../context/AuthContext';
import formatDate from '../utils/formatDate';
import schemeService from '../services/schemeService';
import { toast } from 'react-toastify';

const SchemeCard = ({ scheme, refreshSchemes }) => {
  const { user } = useContext(AuthContext);
  
  const handleBookmark = async (e) => {
    e.preventDefault();
    e.stopPropagation();
    
    if (!user) {
      toast.error('Please log in to bookmark schemes');
      return;
    }
    
    try {
      await schemeService.bookmarkScheme(scheme._id);
      if (refreshSchemes) refreshSchemes();
      toast.success(scheme.isBookmarked ? 'Bookmark removed' : 'Scheme bookmarked');
    } catch (error) {
      toast.error('Failed to update bookmark');
      console.error('Bookmark error:', error);
    }
  };
  
  const truncateText = (text, maxLength = 100) => {
    if (!text || text.length <= maxLength) return text;
    return text.substr(0, maxLength) + '...';
  };
  
  return (
    <Link to={`/schemes/${scheme._id}`} className="block">
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-md hover:shadow-lg transition-shadow p-5 mb-4">
        <div className="flex justify-between items-start mb-3">
          <h3 className="text-xl font-bold text-gray-900 dark:text-white flex-1 pr-3">{scheme.name}</h3>
          {user && (
            <button 
              onClick={handleBookmark}
              className="text-gray-600 dark:text-gray-300 hover:text-green-600 dark:hover:text-green-400"
            >
              {scheme.isBookmarked ? (
                <FaBookmark className="text-green-600 dark:text-green-400" />
              ) : (
                <FaRegBookmark />
              )}
            </button>
          )}
        </div>
        
        <div className="flex items-center text-sm text-gray-500 dark:text-gray-400 mb-3">
          <span className="bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-300 px-2 py-1 rounded">
            {scheme.category || 'General'}
          </span>
          <div className="flex items-center ml-3">
            <FaCalendarAlt className="mr-1" />
            <span>Deadline: {scheme.deadline ? formatDate(scheme.deadline) : 'No deadline'}</span>
          </div>
        </div>
        
        <p className="text-gray-700 dark:text-gray-300 mb-3">{truncateText(scheme.description)}</p>
        
        <div className="border-t border-gray-200 dark:border-gray-700 pt-3 mt-auto">
          <p className="text-sm text-gray-600 dark:text-gray-400">
            <strong>Eligibility:</strong> {truncateText(scheme.eligibility, 70)}
          </p>
          <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
            <strong>Department:</strong> {scheme.department || 'Not specified'}
          </p>
        </div>
      </div>
    </Link>
  );
};

export default SchemeCard;
